gQF(){return"\u0645\u0637\u0648\u0631 Flutter \u0634\u063a\u0648\u0641\u060c \u0623\u0645\u062a\u0644\u0643 \u062e\u0628\u0631\u0629 \u0648\u0627\u0633\u0639\u0629 \u0641\u064a \u0625\u0646\u0634\u0627\u0621 \u062a\u0637\u0628\u064a\u0642\u0627\u062a \u0645\u0648\u0628\u0627\u064a\u0644 \u062a\u0631\u0643\u0632 \u0639\u0644\u0649 \u062a\u062c\u0631\u0628\u0629 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645 Flutter \u0648Bloc \u0648Clean Architecture. \u0644\u062f\u064a \u062e\u0628\u0631\u0629 \u0641\u064a State Management\u060c \u0648\u0627\u0644\u062a\u0643\u0627\u0645\u0644 \u0645\u0639 \u0648\u0627\u062c\u0647\u0627\u062a \u0627\u0644\u0628\u0631\u0645\u062c\u0629 (APIs)\u060c \u0648Firebase\u060c \u0648\u062a\u0637\u0628\u064a\u0642\u0627\u062a \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a. \u0623\u062a\u0645\u064a\u0632 \u0628\u0628\u0646\u0627\u0621 \u0648\u0627\u062c\u0647\u0627\u062a \u0645\u0633\u062a\u062e\u062f\u0645 \u0645\u0631\u0646\u0629 \u0648\u0645\u062a\u062c\u0627\u0648\u0628\u0629 \u0648\u062a\u0642\u062f\u064a\u0645 \u062d\u0644\u0648\u0644 \u0645\u0628\u062a\u0643\u0631\u0629 \u0644\u0644\u062a\u062d\u062f\u064a\u0627\u062a \u0627\u0644\u0645\u0639\u0642\u062f\u0629."},
